"""Sprint68-1Bの可視化4ファイルを完成版へ置換する。"""

from __future__ import annotations

import base64
from pathlib import Path

FILES = {
    Path('app/dashboard/dashboard_web_models.py'): '',
    Path('app/dashboard/dashboard_web_service.py'): '',
    Path('app/dashboard/templates/dashboard.html'): '',
    Path('app/dashboard/static/dashboard.css'): '',
}

for path, payload in FILES.items():
    content = base64.b64decode(payload).decode('utf-8')
    if path.suffix == '.py':
        compile(content, str(path), 'exec')
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(content, encoding='utf-8', newline='\n')
    print(f'updated: {path}')

# Import cacheに依存せず、書き込んだ実ファイルの内容を直接検証する。
models_text = Path('app/dashboard/dashboard_web_models.py').read_text(encoding='utf-8')
service_text = Path('app/dashboard/dashboard_web_service.py').read_text(encoding='utf-8')
html_text = Path('app/dashboard/templates/dashboard.html').read_text(encoding='utf-8')
css_text = Path('app/dashboard/static/dashboard.css').read_text(encoding='utf-8')

checks = {
    'models.drawdown': 'drawdown: float | None = None' in models_text,
    'service.analytics': '_create_daily_history' in service_text,
    'html.drawdown': 'id="drawdown-chart"' in html_text,
    'css.chart-grid': '.chart-grid' in css_text,
}

failed = [name for name, ok in checks.items() if not ok]
if failed:
    raise RuntimeError(f'置換確認に失敗しました: {failed}')

print('Sprint68-1B files were replaced successfully.')
for name in checks:
    print(f'  OK: {name}')
